class Solution {
    public long repairCars(int[] ranks, int cars) {
        long left = 0, right = (long)1e14;
        while (left < right) {
            long mid = left + (right - left) / 2;
            long sum = 0;
            for (int rank : ranks) {
                sum += mid / (rank * rank);
            }
            if (sum < cars) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
}
